/**
 * Returns the sine in degrees from a lookup table. For optimal precision, use degrees between -360 and 360 (both
 * inclusive).
 */
static public float sinDeg(float degrees) {
    return Sin.table[(int) (degrees * degToIndex) & SIN_MASK];
}
